"use client";

import { useTheme } from "next-themes";
import { useEffect, useState } from "react";
import { FloatingTooltip } from "@/components/unlumen-ui/floating-tooltip";

const BF = process.env.NEXT_PUBLIC_BRANDFETCH_CLIENT_ID ?? "";

// ── HELPER: imagem Brandfetch com URL explícita por tema ────────────────────
function BfImg({
  darkSrc,
  lightSrc,
  name,
  className = "h-8 w-auto max-w-[88px] object-contain",
}: {
  darkSrc: string;
  lightSrc?: string;
  name: string;
  className?: string;
}) {
  const { resolvedTheme } = useTheme();
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);
  if (!mounted) return <div className="h-8 w-20" />;
  const src = resolvedTheme === "light" && lightSrc ? lightSrc : darkSrc;
  return <img src={src} alt={name} className={className} loading="lazy" />;
}

// ── HELPER: ícone Brandfetch padrão (único URL, serve ambos os modos) ────────
function BfIcon({ domain, name }: { domain: string; name: string }) {
  const { resolvedTheme } = useTheme();
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);
  if (!mounted) return <div className="w-8 h-8" />;
  const t = resolvedTheme === "light" ? "light" : "dark";
  return (
    <img
      src={`https://cdn.brandfetch.io/${domain}/theme/${t}/icon?c=${BF}&fallback=monogram`}
      alt={name}
      className="w-8 h-8 object-contain"
      loading="lazy"
    />
  );
}

// ── UBIQUITI — Brandfetch oficial (dark/light) ──────────────────────────────
function UbiquitiIcon() {
  return (
    <BfImg
      name="Ubiquiti"
      darkSrc="https://cdn.brandfetch.io/domain/ui.com/w/800/h/244/theme/light/logo?c=1idKxZOOI6oTBbTNMDo"
      lightSrc="https://cdn.brandfetch.io/domain/ui.com/w/800/h/244/logo?c=1idKxZOOI6oTBbTNMDo"
      className="h-5 w-auto max-w-[100px] object-contain"
    />
  );
}

