// ── STARLINK — wordmark preta; invert() no dark mode ────────────────────────
function StarlinkLogo() {
  const { resolvedTheme } = useTheme();
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);
  if (!mounted) return <div className="h-4 w-16" />;
  const filter = resolvedTheme === "dark" ? "invert(1)" : "none";
  return (
    <img
      src={`https://cdn.brandfetch.io/starlink.com/w/800/h/147/logo?c=${BF}`}
      alt="Starlink"
      className="h-4 w-auto max-w-[80px] object-contain"
      style={{ filter }}
      loading="lazy"
    />
  );
}

